12→export function polygonArea(points) {
13→  let area = 0;
14→  const n = points.length;
15→  for (let i = 0; i < n; i++) {
16→    const j = (i + 1) % n;
17→    area += points[i].x * points[j].y;
18→    area -= points[j].x * points[i].y;
19→  }
20→  return Math.abs(area) / 2;
21→}
